## Eino 框架中的两种中断恢复方式

---

## 方式一：通过 Middleware 拦截

这种方式是在 **Agent 层面**通过中间件拦截 Tool 调用，适用于：
- 需要对多个 Tool 统一处理审批逻辑
- 不想修改原有 Tool 的实现
- 需要灵活配置哪些 Tool 需要审批

### 完整示例

```go
package main

import (
	"context"
	"fmt"
	"os"

	"github.com/cloudwego/eino/components/tool"
	"github.com/cloudwego/eino/flow/adk"
	adkstore "github.com/cloudwego/eino/flow/adk/store"
	"github.com/cloudwego/eino/schema"
)

// ApprovalInfo 审批信息，会展示给用户
type ApprovalInfo struct {
	ToolName        string
	ArgumentsInJSON string
}

func (ai *ApprovalInfo) String() string {
	return fmt.Sprintf("⚠️ Approval Required\nTool: %s\nArguments: %s\nApprove? (y/n): ",
		ai.ToolName, ai.ArgumentsInJSON)
}

// ApprovalResult 审批结果
type ApprovalResult struct {
	Approved         bool
	DisapproveReason *string
}

func init() {
	schema.Register[*ApprovalInfo]()
}

// ApprovalMiddleware 审批中间件
type ApprovalMiddleware struct {
	*adk.BaseChatModelAgentMiddleware
	toolsToApprove map[string]bool // 需要审批的 Tool 名称
}

func NewApprovalMiddleware(toolsToApprove ...string) *ApprovalMiddleware {
	m := &ApprovalMiddleware{
		toolsToApprove: make(map[string]bool),
	}
	for _, t := range toolsToApprove {
		m.toolsToApprove[t] = true
	}
	return m
}

// WrapInvokableToolCall 拦截同步 Tool 调用
func (m *ApprovalMiddleware) WrapInvokableToolCall(
	_ context.Context,
	endpoint adk.InvokableToolCallEndpoint,
	tCtx *adk.ToolContext,
) (adk.InvokableToolCallEndpoint, error) {
	// 只拦截需要审批的 Tool
	if !m.toolsToApprove[tCtx.Name] {
		return endpoint, nil
	}

	return func(ctx context.Context, args string, opts ...tool.Option) (string, error) {
		// 获取中断状态
		wasInterrupted, _, storedArgs := tool.GetInterruptState[string](ctx)

		if !wasInterrupted {
			// 第一次调用：触发中断，保存参数
			return "", tool.StatefulInterrupt(ctx, &ApprovalInfo{
				ToolName:        tCtx.Name,
				ArgumentsInJSON: args,
			}, args)
		}

		// Resume 后：获取审批结果
		isTarget, hasData, data := tool.GetResumeContext[*ApprovalResult](ctx)
		if isTarget && hasData {
			if data.Approved {
				// 用户批准：执行原 Tool
				return endpoint(ctx, storedArgs, opts...)
			}
			// 用户拒绝
			if data.DisapproveReason != nil {
				return fmt.Sprintf("tool '%s' disapproved: %s", tCtx.Name, *data.DisapproveReason), nil
			}
			return fmt.Sprintf("tool '%s' disapproved", tCtx.Name), nil
		}

		// 其他情况：重新中断
		return "", tool.StatefulInterrupt(ctx, &ApprovalInfo{
			ToolName:        tCtx.Name,
			ArgumentsInJSON: storedArgs,
		}, storedArgs)
	}, nil
}

// ========== 使用示例 ==========

func main() {
	ctx := context.Background()

	// 1. 创建 Agent，添加审批中间件
	agent, err := adk.NewReactAgent(ctx, &adk.ReactAgentConfig{
		Model: createModel(),
		Tools: []tool.InvokableTool{
			createExecuteTool(),  // 危险操作
			createReadFileTool(), // 安全操作
		},
		// 添加中间件：只审批 execute 工具
		Handlers: []adk.ChatModelAgentMiddleware{
			NewApprovalMiddleware("execute"),
		},
	})
	if err != nil {
		panic(err)
	}

	// 2. 创建 Runner，配置 CheckPointStore（必须）
	runner := adk.NewRunner(ctx, adk.RunnerConfig{
		Agent:           agent,
		EnableStreaming: true,
		CheckPointStore: adkstore.NewInMemoryStore(),
	})

	// 3. 运行并处理中断
	sessionID := "session-001"
	history := []*schema.Message{
		schema.UserMessage("请执行命令 echo hello"),
	}

	events := runner.Run(ctx, history, adk.WithCheckPointID(sessionID))
	for event := range events {
		if event.Interrupt != nil {
			// 处理中断
			approvalInfo := event.Interrupt.Data.(*ApprovalInfo)
			fmt.Println(approvalInfo.String())

			// 读取用户输入
			var input string
			fmt.Scanln(&input)

			// 构造审批结果
			result := &ApprovalResult{Approved: input == "y" || input == "Y"}

			// 恢复执行
			resumeEvents := runner.ResumeWith(ctx, sessionID, result)
			for e := range resumeEvents {
				fmt.Println(e)
			}
		} else {
			fmt.Println(event)
		}
	}
}
```

