## 方式二：定义 Tool 时专门处理

这种方式是在 **Tool 内部**直接实现中断逻辑，适用于：
- 特定 Tool 需要特殊的审批逻辑
- 审批逻辑与 Tool 紧密相关
- 需要 Tool 自带审批能力

### 完整示例

```go
package main

import (
	"context"
	"fmt"
	"os/exec"

	"github.com/cloudwego/eino/components/tool"
	"github.com/cloudwego/eino/schema"
)

// ApprovalInfo 审批信息
type ApprovalInfo struct {
	ToolName        string
	ArgumentsInJSON string
}

func (ai *ApprovalInfo) String() string {
	return fmt.Sprintf("⚠️ Approval Required\nTool: %s\nArguments: %s\nApprove? (y/n): ",
		ai.ToolName, ai.ArgumentsInJSON)
}

// ApprovalResult 审批结果
type ApprovalResult struct {
	Approved         bool
	DisapproveReason *string
}

func init() {
	schema.Register[*ApprovalInfo]()
}

// ApprovableExecuteTool 自带审批功能的执行命令工具
type ApprovableExecuteTool struct {
	info *schema.ToolInfo
}

func NewApprovableExecuteTool() *ApprovableExecuteTool {
	return &ApprovableExecuteTool{
		info: &schema.ToolInfo{
			Name: "execute",
			Desc: "执行 shell 命令（需要审批）",
			ParamsOneOf: schema.NewParamsOneOfByParams(map[string]any{
				"command": map[string]any{
					"type":        "string",
					"description": "要执行的命令",
				},
			}),
		},
	}
}

func (t *ApprovableExecuteTool) Info(ctx context.Context) (*schema.ToolInfo, error) {
	return t.info, nil
}

// InvokableRun Tool 的核心逻辑，包含中断处理
func (t *ApprovableExecuteTool) InvokableRun(ctx context.Context, argumentsInJSON string, opts ...tool.Option) (string, error) {
	// ========== 中断恢复逻辑 ==========

	// 1. 检查是否是 Resume 后的调用
	wasInterrupted, _, storedArgs := tool.GetInterruptState[string](ctx)

	if !wasInterrupted {
		// 第一次调用：触发中断，保存参数
		return "", tool.StatefulInterrupt(ctx, &ApprovalInfo{
			ToolName:        "execute",
			ArgumentsInJSON: argumentsInJSON,
		}, argumentsInJSON)
	}

	// 2. Resume 后：获取审批结果
	isTarget, hasData, data := tool.GetResumeContext[*ApprovalResult](ctx)

	if isTarget && hasData {
		// 用户已做出决定
		if data.Approved {
			// 用户批准：执行命令
			return t.executeCommand(storedArgs)
		}

		// 用户拒绝
		if data.DisapproveReason != nil {
			return fmt.Sprintf("Command rejected: %s", *data.DisapproveReason), nil
		}
		return "Command rejected by user", nil
	}

	// 3. 如果 Resume 目标不是当前 Tool，重新中断
	isResumeTarget, _, _ := tool.GetResumeContext[any](ctx)
	if !isResumeTarget {
		return "", tool.StatefulInterrupt(ctx, &ApprovalInfo{
			ToolName:        "execute",
			ArgumentsInJSON: storedArgs,
		}, storedArgs)
	}

	// 4. 其他情况：执行命令
	return t.executeCommand(storedArgs)
}

// executeCommand 实际执行命令
func (t *ApprovableExecuteTool) executeCommand(args string) (string, error) {
	// 解析参数并执行命令
	// 这里简化处理，实际需要解析 JSON
	cmd := exec.Command("sh", "-c", args)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return "", err
	}
	return string(output), nil
}

// ========== 使用示例 ==========

func main() {
	ctx := context.Background()

	// 1. 创建自带审批的 Tool
	execTool := NewApprovableExecuteTool()

	// 2. 创建 Agent（不需要中间件）
	agent, err := adk.NewReactAgent(ctx, &adk.ReactAgentConfig{
		Model: createModel(),
		Tools: []tool.InvokableTool{execTool},
	})
	if err != nil {
		panic(err)
	}

	// 3. 创建 Runner（仍需要 CheckPointStore）
	runner := adk.NewRunner(ctx, adk.RunnerConfig{
		Agent:           agent,
		CheckPointStore: adkstore.NewInMemoryStore(),
	})

	// 4. 运行并处理中断
	sessionID := "session-001"
	history := []*schema.Message{
		schema.UserMessage("请执行命令 ls -la"),
	}

	events := runner.Run(ctx, history, adk.WithCheckPointID(sessionID))
	for event := range events {
		if event.Interrupt != nil {
			approvalInfo := event.Interrupt.Data.(*ApprovalInfo)
			fmt.Println(approvalInfo.String())

			var input string
			fmt.Scanln(&input)

			result := &ApprovalResult{Approved: input == "y"}

			resumeEvents := runner.ResumeWith(ctx, sessionID, result)
			for e := range resumeEvents {
				fmt.Println(e)
			}
		}
	}
}
```

