### 方式三：使用 Stream 模式手动处理

适合需要精细控制中断恢复的场景：

```go
// 创建 Runner
runner, _ := productionrunner.New(ctx, productionrunner.RunnerConfig{
    Agent:           agent,
    CheckPointStore: productionrunner.NewInMemoryStore(),
})

// 使用 Stream 获取事件迭代器
iter := runner.Stream(ctx, "执行敏感操作", 
    productionrunner.WithCheckPointID("session-001"))

var interruptInfo *InterruptInfo

// 逐个处理事件
for {
    evt, ok := iter.Next()
    if !ok {
        break
    }

    switch evt.Type {
    case productionrunner.EventTypeOutput:
        fmt.Printf("输出: %s\n", evt.Message.Content)

    case productionrunner.EventTypeToolCall:
        fmt.Printf("工具调用: %s\n", evt.ToolCalls[0].Name)

    case productionrunner.EventTypeInterrupt:
        // 捕获中断信息
        interruptInfo = evt.Interrupt
        fmt.Printf("中断: ID=%s, Info=%v\n", evt.Interrupt.ID, evt.Interrupt.Info)
        // 可以在这里保存中断状态到数据库

    case productionrunner.EventTypeError:
        fmt.Printf("错误: %v\n", evt.Error)
    }
}

// 获取最终结果
result := iter.Result()

// 如果中断，稍后恢复
if result.Interrupted && interruptInfo != nil {
    // 用户批准后恢复
    resumeResult := runner.Resume(ctx, &productionrunner.ResumeParams{
        CheckPointID: "session-001",
        Targets: map[string]any{
            interruptInfo.ID: &ApprovalResult{Approved: true},
        },
    })
}
```

