### 完整示例：统一审批系统

```go
package main

import (
    "context"
    "fmt"
    "log"

    "github.com/cloudwego/eino/adk"
    "github.com/cloudwego/eino/schema"

    productionrunner "your-project/production-runner"
)

// ApprovalResult 审批结果
type ApprovalResult struct {
    Approved bool
    Reason   *string
}

func init() {
    schema.Register[*ApprovalResult]()
}

func main() {
    ctx := context.Background()

    // 1. 创建 Agent（带有需要审批的工具）
    agent := createAgentWithApprovalTools(ctx)

    // 2. 创建审批处理器
    approvalHandler := productionrunner.NewApprovalHandler()
    approvalHandler.AutoApprove("read_file") // 自动批准 read_file
    approvalHandler.SetApprovalCallback(handleApproval)

    // 3. 组合多个处理器：日志 + 指标 + 审批
    compositeHandler := productionrunner.NewCompositeHandler(
        productionrunner.NewDefaultHandler(log.Default(), true),
        productionrunner.NewMetricsHandler(),
        approvalHandler,
    )

    // 4. 创建 Runner
    runner, err := productionrunner.New(ctx, productionrunner.RunnerConfig{
        Agent:           agent,
        EnableStreaming: true,
        CheckPointStore: productionrunner.NewInMemoryStore(),
    }, productionrunner.WithHandler(compositeHandler))
    if err != nil {
        log.Fatal(err)
    }

    // 5. 运行
    sessionID := "session-001"
    result := runner.Run(ctx, "请删除 /tmp 目录下的所有文件", 
        productionrunner.WithCheckPointID(sessionID))

    // 6. 处理中断
    if result.Interrupted {
        fmt.Println("需要人工审批...")

        // 模拟用户批准
        resumeResult := runner.Resume(ctx, &productionrunner.ResumeParams{
            CheckPointID: sessionID,
            Targets: map[string]any{
                result.Interrupt.ID: &ApprovalResult{Approved: true},
            },
        })

        fmt.Printf("恢复结果: %v\n", resumeResult.Success)
    }
}

// handleApproval 人工审批处理
func handleApproval(ctx context.Context, info *InterruptInfo) (bool, *string) {
    fmt.Printf("\n========== 审批请求 ==========\n")
    fmt.Printf("中断ID: %s\n", info.ID)
    fmt.Printf("信息: %v\n", info.Info)
    fmt.Printf("状态: %v\n", info.State)
    fmt.Print("\n批准？(Y/N): ")

    var input string
    fmt.Scanln(&input)

    if input == "Y" || input == "y" {
        return true, nil
    }
    reason := "用户拒绝操作"
    return false, &reason
}
```

